<template><div class="page"><div class="header"><div><h1>数据导出管理</h1><p>普通导出仅允许脱敏字段；敏感字段必须申请、审批并显式执行。</p></div><div><el-button v-if="canNormal" @click="open('NORMAL')">普通脱敏导出</el-button><el-button v-if="canSensitive" type="primary" @click="open('SENSITIVE')">敏感导出申请</el-button></div></div><el-alert v-if="error" title="导出记录加载失败" type="error" :closable="false" show-icon><el-button link type="primary" @click="load">重试</el-button></el-alert><el-card shadow="never"><el-table v-loading="loading" :data="records" empty-text="查询成功，暂无导出记录"><el-table-column prop="exportNo" label="导出编号" min-width="180"/><el-table-column prop="exportModule" label="模块" width="120"/><el-table-column prop="exportType" label="类型" min-width="140"/><el-table-column prop="rowCount" label="行数" width="80"/><el-table-column prop="status" label="状态" width="100"/><el-table-column prop="createdAt" label="创建时间" min-width="170"/><el-table-column label="操作" width="90"><template #default="{row}"><el-button v-if="row.downloadable" link type="primary" @click="download(row)">下载</el-button></template></el-table-column></el-table><AppPagination v-model:current="query.current" v-model:size="query.size" :total="total" @change="load"/></el-card><FormDialog v-model:visible="visible" :title="mode==='NORMAL'?'普通脱敏导出':'敏感导出申请'" :loading="submitting" @confirm="submit"><el-form ref="formRef" :model="form" :rules="rules" label-width="100px"><el-form-item label="模块"><el-select v-model="form.module"><el-option label="人口" value="PERSON"/></el-select></el-form-item><el-form-item label="导出字段" prop="fields"><el-checkbox-group v-model="form.fields"><el-checkbox value="name">姓名</el-checkbox><el-checkbox value="maskedIdentityNo">脱敏身份证</el-checkbox><el-checkbox value="maskedPhone">脱敏手机</el-checkbox><el-checkbox value="regionCode">区划</el-checkbox><el-checkbox v-if="mode==='SENSITIVE'" value="identityNo">完整身份证</el-checkbox><el-checkbox v-if="mode==='SENSITIVE'" value="phone">完整手机</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="区划筛选"><RegionCascader v-model="form.regionCode"/></el-form-item><template v-if="mode==='SENSITIVE'"><el-form-item label="申请标题" prop="title"><el-input v-model.trim="form.title"/></el-form-item><el-form-item label="导出理由" prop="reason"><el-input v-model.trim="form.reason" type="textarea"/></el-form-item><el-form-item label="预计行数" prop="expectedRowLimit"><el-input-number v-model="form.expectedRowLimit" :min="1" :max="10000"/></el-form-item></template></el-form></FormDialog></div></template>
<script setup>
import { computed,onMounted,reactive,ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import AppPagination from '../../components/common/AppPagination.vue';import FormDialog from '../../components/common/FormDialog.vue';import RegionCascader from '../../components/business/RegionCascader.vue';import { createNormalExport,createSensitiveExport,downloadExport,getExportPage } from '../../api/exports.js';import { normalizePageResult } from '../../utils/page.js';import { useUserStore } from '../../stores/user.js';import { PERMISSIONS } from '../../constants/permissions.js'
const router=useRouter(),user=useUserStore();const canNormal=computed(()=>user.hasPermission(PERMISSIONS.DATA_EXPORT_NORMAL)),canSensitive=computed(()=>user.hasPermission(PERMISSIONS.DATA_EXPORT_SENSITIVE_APPLY));const query=reactive({current:1,size:10});const records=ref([]),total=ref(0),loading=ref(false),error=ref(false),visible=ref(false),submitting=ref(false),mode=ref('NORMAL'),formRef=ref();const form=reactive({module:'PERSON',fields:['name','maskedIdentityNo','maskedPhone','regionCode'],regionCode:'',title:'敏感数据导出',reason:'',expectedRowLimit:100});const rules={fields:[{type:'array',required:true,min:1,message:'请选择字段'}],title:[{required:true,message:'请输入标题'}],reason:[{required:true,message:'请输入理由'}],expectedRowLimit:[{required:true,message:'请输入预计行数'}]}
async function load(){loading.value=true;try{const p=normalizePageResult(await getExportPage(query));records.value=p.records;total.value=p.total;error.value=false}catch{error.value=true}finally{loading.value=false}}function open(type){mode.value=type;form.fields=['name','maskedIdentityNo','maskedPhone','regionCode'];visible.value=true}async function submit(){if(!await formRef.value?.validate())return;submitting.value=true;try{const filters=form.regionCode?{regionCode:form.regionCode}:{};if(mode.value==='NORMAL'){await createNormalExport({module:form.module,filters,fields:form.fields});ElMessage.success('脱敏导出已生成');visible.value=false;load()}else{const id=await createSensitiveExport({module:form.module,filters,fields:form.fields,reason:form.reason,expectedRowLimit:form.expectedRowLimit,title:form.title});ElMessage.success('敏感导出申请已创建，请上传用途说明后提交');visible.value=false;router.push(`/applications/${id}`)}}finally{submitting.value=false}}async function download(row){const blob=await downloadExport(row.exportLogId);const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=row.fileName||`${row.exportNo}.xlsx`;a.click();URL.revokeObjectURL(url)}onMounted(load)
</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.header{display:flex;justify-content:space-between;align-items:flex-end}.header h1{margin:0 0 6px}.header p{color:var(--el-text-color-secondary)}</style>
